+
+    if output.status.success() {
+        let stdout = String::from_utf8_lossy(&output.stdout);
+        if stdout.contains("copilot") {
+            Some("Copilot extension installed".to_string())
+        } else {
+            Some("gh found but Copilot extension not installed".to_string())
+        }
+    } else {
+        None
+    }
+}
